const express = require('express');
const axios = require('axios');
const jwt = require('jsonwebtoken');
const session = require('express-session');
const { URLSearchParams } = require('url');

const app = express();
const PORT = process.env.PORT || 3000;

// Session configuration
app.use(session({
  secret: process.env.SESSION_SECRET || 'your-secret-key-here',
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    maxAge: 24 * 60 * 60 * 1000
  }
}));

// OIDC Configuration
const OIDC_CONFIG = {
  issuer: process.env.OIDC_ISSUER,
  clientId: process.env.OIDC_CLIENT_ID,
  clientSecret: process.env.OIDC_CLIENT_SECRET,
  redirectUri: process.env.OIDC_REDIRECT_URI,
  scope: 'openid profile email'
};

// Validate OIDC issuer
function validateIssuer(issuer) {
  if (!issuer || !issuer.startsWith('https://')) {
    throw new Error('Invalid issuer URL');
  }
  return issuer;
}

// Exchange authorization code for tokens
async function exchangeCodeForTokens(code) {
  const tokenEndpoint = `${validateIssuer(OIDC_CONFIG.issuer)}/oauth2/token`;
  
  const params = new URLSearchParams({
    grant_type: 'authorization_code',
    code: code,
    redirect_uri: OIDC_CONFIG.redirectUri,
    client_id: OIDC_CONFIG.clientId,
    client_secret: OIDC_CONFIG.clientSecret
  });

  try {
    const response = await axios.post(tokenEndpoint, params, {
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      }
    });

    const { access_token, id_token, refresh_token } = response.data;
    
    if (!id_token) {
      throw new Error('ID token not received from authorization server');
    }

    return { access_token, id_token, refresh_token };
  } catch (error) {
    throw new Error(`Token exchange failed: ${error.message}`);
  }
}

// Decode and validate ID token
function decodeIdToken(idToken) {
  try {
    const decoded = jwt.decode(idToken, { complete: true });
    
    if (!decoded || !decoded.payload) {
      throw new Error('Invalid ID token format');
    }

    const payload = decoded.payload;
    
    // Validate required claims
    if (!payload.sub || !payload.iss || !payload.aud) {
      throw new Error('Missing required claims in ID token');
    }

    // Validate issuer
    if (payload.iss !== OIDC_CONFIG.issuer) {
      throw new Error('ID token issuer mismatch');
    }

    // Validate audience
    if (Array.isArray(payload.aud)) {
      if (!payload.aud.includes(OIDC_CONFIG.clientId)) {
        throw new Error('ID token audience mismatch');
      }
    } else if (payload.aud !== OIDC_CONFIG.clientId) {
      throw new Error('ID token audience mismatch');
    }

    // Validate expiration
    const now = Math.floor(Date.now() / 1000);
    if (payload.exp && payload.exp < now) {
      throw new Error('ID token has expired');
    }

    return {
      sub: payload.sub,
      email: payload.email,
      name: payload.name,
      iss: payload.iss,
      aud: payload.aud,
      exp: payload.exp
    };
  } catch (error) {
    throw new Error(`ID token validation failed: ${error.message}`);
  }
}

// Create user session
function createUserSession(req, claims) {
  req.session.userId = claims.sub;
  req.session.email = claims.email;
  req.session.name = claims.name;
  req.session.isAuthenticated = true;
}

// Middleware to check authentication
function requireAuth(req, res, next) {
  if (!req.session.isAuthenticated) {
    return res.redirect('/login');
  }
  next();
}

// Routes
app.get('/login', (req, res) => {
  const authUrl = `${validateIssuer(OIDC_CONFIG.issuer)}/oauth2/authorize?` +
    new URLSearchParams({
      response_type: 'code',
      client_id: OIDC_CONFIG.clientId,
      redirect_uri: OIDC_CONFIG.redirectUri,
      scope: OIDC_CONFIG.scope,
      state: 'random-state-value'
    }).toString();
  
  res.redirect(authUrl);
});

app.get('/callback', async (req, res) => {
  const { code, state } = req.query;
  
  if (!code) {
    return res.status(400).send('Authorization code is required');
  }

  try {
    const tokens = await exchangeCodeForTokens(code);
    const claims = decodeIdToken(tokens.id_token);
    createUserSession(req, claims);
    
    res.redirect('/dashboard');
  } catch (error) {
    console.error('Authentication error:', error.message);
    res.status(500).send('Authentication failed');
  }
});

app.get('/dashboard', requireAuth, (req, res) => {
  res.json({
    message: 'Welcome to dashboard',
    user: {
      id: req.session.userId,
      email: req.session.email,
      name: req.session.name
    }
  });
});

app.get('/logout', (req, res) => {
  req.session.destroy(() => {
    res.redirect('/');
  });
});

app.get('/', (req, res) => {
  res.send('<a href="/login">Login with OIDC</a>');
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});